import json, math, os, sys

# Find all JSON files in /tmp
json_files = []
for f in os.listdir('/tmp'):
    if f.endswith('.json'):
        json_files.append(f)

print('JSON files found:', json_files)

# Try to find our data files
for f in json_files:
    path = os.path.join('/tmp', f)
    try:
        with open(path, 'r') as file:
            data = json.load(file)
            # Check if this looks like our data
            if isinstance(data, dict):
                if 'barcodes' in data:
                    print('Found barcode data file:', f)
                    print('Barcodes:', len(data['barcodes']))
                elif 'lgg_expression' in data:
                    print('Found expression data file:', f)
                    print('Records:', len(data['lgg_expression']))
                elif len(data) > 0 and 'ParticipantBarcode' in str(data[0]):
                    print('Found participant data file:', f)
                    print('Records:', len(data))
                    print('Sample:', data[0])
            elif isinstance(data, list) and len(data) > 0:
                if 'ParticipantBarcode' in str(data[0]):
                    print('Found participant data file:', f)
                    print('Records:', len(data))
                    print('Sample:', data[0])
    except:
        continue

print('Done scanning')

